133	func Capabilities() CapabilityReport {
134		extensions := make([]string, 0, len(treeSitterLanguages))
135		languageSet := map[string]struct{}{}
136		for extension, spec := range treeSitterLanguages {
137			extensions = append(extensions, extension)
138			languageSet[spec.language] = struct{}{}
139		}
140		sort.Strings(extensions)
141		languages := make([]string, 0, len(languageSet))
142		for language := range languageSet {
143			languages = append(languages, language)
144		}
145		sort.Strings(languages)
146	
147		return CapabilityReport{
148			SchemaVersion:                   SchemaVersion,
149			Provider:                        ProviderName,
150			SupportedFileExtensions:         extensions,
151			SupportedLanguages:              languages,
152			UnsupportedButDetectedLanguages: []string{},
153			ParserVersions: map[string]string{
154				"go-tree-sitter": "github.com/smacker/go-tree-sitter",
155			},
156			SupportedRelationTypes: append([]string(nil), relationTypes...),
157			OptionalLocalOnlyFeatures: map[string]bool{
158				"stable_symbol_ids": true,
159				"semantic_diff":     true,
160				"ndjson_snapshot":   true,
161			},
162			FeaturesRequiringNetworkAccess: map[string]bool{
163				"grammar_download":  false,
164				"hosted_models":     false,
165				"remote_embeddings": false,
166				"telemetry_upload":  false,
167				"remote_code_fetch": false,
168				"network_discovery": false,
169			},
170		}
171	}
