173	func BuildProviderSnapshot(ctx context.Context, repo, providerVersion string) (ProviderSnapshot, error) {
174		absRepo, err := filepath.Abs(repo)
175		if err != nil {
176			return ProviderSnapshot{}, err
177		}
178		repoKey := repoKey(ctx, absRepo)
179		var warnings []ProviderWarning
180		commit, commitErr := gitutil.RevParse(ctx, absRepo, "HEAD")
181		tree, treeErr := gitutil.RevParse(ctx, absRepo, "HEAD^{tree}")
182	
183		paths, contentByFile, err := snapshotSource(ctx, absRepo, commitErr == nil && treeErr == nil)
184		if err != nil {
185			return ProviderSnapshot{}, err
186		}
187		if commitErr != nil || treeErr != nil {
188			warnings = append(warnings, ProviderWarning{
189				Code:                 "E_NO_GIT_HEAD",
190				Severity:             "warning",
191				EffectOnCompleteness: "snapshot records are read from the working tree because no HEAD tree is available",
192				Detail:               firstError(commitErr, treeErr).Error(),
193			})
194		}
195	
196		parser := TreeSitterParser{}
197		languageSet := map[string]struct{}{}
198		var files []FileRecord
199		var symbols []SymbolRecord
200		var failures []PartialFailure
201		recordsByFile := map[string][]SymbolRecord{}
202	
203		for _, path := range paths {
204			if !Supported(path) {
205				if hint := unsupportedLanguageHint(path); hint != "" {
206					failures = append(failures, PartialFailure{
207						Code:                 "E_UNSUPPORTED_LANGUAGE",
208						Severity:             "warning",
209						FilePath:             path,
210						EffectOnCompleteness: "file omitted because no parser is available",
211						Detail:               hint,
212					})
213				}
214				continue
215			}
216			content, ok := contentByFile[path]
217			if !ok {
218				failures = append(failures, PartialFailure{
219					Code:                 "E_FILE_READ",
220					Severity:             "error",
221					FilePath:             path,
222					EffectOnCompleteness: "file omitted from semantic snapshot",
223					Detail:               "file listed but content was unavailable",
224				})
225				continue
226			}
227			entities, language := parser.Parse(path, content)
228			if language == "" {
229				failures = append(failures, PartialFailure{
230					Code:                 "E_UNSUPPORTED_LANGUAGE",
231					Severity:             "warning",
232					FilePath:             path,
233					EffectOnCompleteness: "file omitted because no parser is available",
234				})
235				continue
236			}
237			languageSet[language] = struct{}{}
238			contentBytes := []byte(content)
239			files = append(files, FileRecord{
240				RecordType: "file",
241				Path:       path,
242				Blob:       contentHash(contentBytes),
243				Language:   language,
244				Bytes:      len(contentBytes),
245			})
246			fileSymbols := entitySymbols(repoKey, path, language, entities)
247			symbols = append(symbols, fileSymbols...)
248			recordsByFile[path] = fileSymbols
249		}
250	
251		relations := buildRelations(repoKey, files, recordsByFile, contentByFile)
252		languages := sortedKeys(languageSet)
253		if warnings == nil {
254			warnings = []ProviderWarning{}
255		}
256		if failures == nil {
257			failures = []PartialFailure{}
258		}
259		header := SnapshotHeader{
260			SchemaVersion:   SchemaVersion,
261			Provider:        ProviderName,
262			ProviderVersion: providerVersion,
263			RepoRoot:        absRepo,
264			RepoKey:         repoKey,
265			Commit:          commit,
266			Tree:            tree,
267			Languages:       languages,
268			Capabilities:    []string{"ndjson", "stable-symbol-id-v1", "local-only", "partial-failures"},
269			Warnings:        warnings,
270			PartialFailures: failures,
271			Stats: ProviderStats{
272				Files:             len(files),
273				ParsedFiles:       len(recordsByFile),
274				Symbols:           len(symbols),
275				Relations:         len(relations),
276				PartialFailures:   len(failures),
277				CompletenessLevel: completenessLevel(len(failures), len(files)),
278			},
279		}
280		return ProviderSnapshot{Header: header, Files: files, Symbols: symbols, Relations: relations}, nil
281	}
