323	func entitySymbols(repoKey, path, language string, entities []Entity) []SymbolRecord {
324		byName := map[string]string{}
325		var symbols []SymbolRecord
326		for _, entity := range entities {
327			qualified := entity.Name
328			id := symbolID(repoKey, language, path, entity.Kind, qualified)
329			containerID := ""
330			if containerName := containerName(qualified); containerName != "" {
331				if parentID, ok := byName[containerName]; ok {
332					containerID = parentID
333				}
334			}
335			symbol := SymbolRecord{
336				RecordType:      "symbol",
337				ID:              id,
338				StableIDVersion: StableSymbolIDVersion,
339				Kind:            entity.Kind,
340				Name:            shortEntityName(entity.Name),
341				QualifiedName:   qualified,
342				FilePath:        path,
343				StartLine:       entity.StartLine,
344				EndLine:         entity.EndLine,
345				Signature:       entity.Signature,
346				BodyHash:        entity.BodyHash,
347				Language:        language,
348				ContainerID:     containerID,
349			}
350			symbols = append(symbols, symbol)
351			byName[qualified] = id
352		}
353		return symbols
354	}
