356	func buildRelations(repoKey string, files []FileRecord, recordsByFile map[string][]SymbolRecord, contentByFile map[string]string) []RelationRecord {
357		var relations []RelationRecord
358		symbolsByShortName := map[string][]SymbolRecord{}
359		for _, records := range recordsByFile {
360			for _, symbol := range records {
361				relations = append(relations, RelationRecord{
362					RecordType:   "relation",
363					FromID:       fileID(repoKey, symbol.FilePath),
364					ToID:         symbol.ID,
365					Type:         "DEFINES",
366					Confidence:   1,
367					Reason:       "symbol parsed from file",
368					WarningCodes: []string{},
369				})
370				if symbol.ContainerID != "" {
371					relations = append(relations, RelationRecord{
372						RecordType:   "relation",
373						FromID:       symbol.ContainerID,
374						ToID:         symbol.ID,
375						Type:         "CONTAINS",
376						Confidence:   1,
377						Reason:       "symbol qualified name is nested in container",
378						WarningCodes: []string{},
379					})
380				}
381				symbolsByShortName[symbol.Name] = append(symbolsByShortName[symbol.Name], symbol)
382			}
383		}
384	
385		for _, file := range files {
386			content, ok := contentByFile[file.Path]
387			if !ok {
388				continue
389			}
390			fromID := fileID(repoKey, file.Path)
391			for _, imported := range importsFor(file.Path, content) {
392				relations = append(relations, RelationRecord{
393					RecordType:   "relation",
394					FromID:       fromID,
395					ToID:         externalID("import", imported),
396					Type:         "IMPORTS",
397					Confidence:   0.8,
398					Reason:       "import declaration matched by language-specific scanner",
399					WarningCodes: []string{},
400				})
401			}
402			for _, from := range recordsByFile[file.Path] {
403				block := symbolBlock(content, from)
404				for name, candidates := range symbolsByShortName {
405					if name == from.Name || !containsIdentifier(block, name) {
406						continue
407					}
408					for _, to := range candidates {
409						if to.ID == from.ID {
410							continue
411						}
412						relations = append(relations, RelationRecord{
413							RecordType:   "relation",
414							FromID:       from.ID,
415							ToID:         to.ID,
416							Type:         "CALLS",
417							Confidence:   0.62,
418							Reason:       "identifier reference inside symbol body matches known symbol name",
419							WarningCodes: []string{},
420						})
421					}
422				}
423				for _, route := range routeLiterals(block) {
424					relations = append(relations, RelationRecord{
425						RecordType:   "relation",
426						FromID:       from.ID,
427						ToID:         externalID("route", route),
428						Type:         "HANDLES_ROUTE",
429						Confidence:   0.7,
430						Reason:       "route-like string literal found inside handler symbol",
431						WarningCodes: []string{},
432					})
433				}
434				if looksLikeToolHandler(from, block) {
435					relations = append(relations, RelationRecord{
436						RecordType:   "relation",
437						FromID:       from.ID,
438						ToID:         externalID("tool", from.QualifiedName),
439						Type:         "HANDLES_TOOL",
440						Confidence:   0.58,
441						Reason:       "symbol name or body contains tool handler vocabulary",
442						WarningCodes: []string{},
443					})
444				}
445			}
446		}
447	
448		sort.Slice(relations, func(i, j int) bool {
449			left := relations[i].Type + relations[i].FromID + relations[i].ToID
450			right := relations[j].Type + relations[j].FromID + relations[j].ToID
451			return left < right
452		})
453		return dedupeRelations(relations)
454	}
