456	func snapshotSource(ctx context.Context, repo string, useHead bool) ([]string, map[string]string, error) {
457		if useHead {
458			paths, err := gitutil.ListFiles(ctx, repo, "HEAD")
459			if err != nil {
460				return nil, nil, err
461			}
462			contentByFile := map[string]string{}
463			for _, path := range paths {
464				content, ok, err := gitutil.ShowFile(ctx, repo, "HEAD", path)
465				if err != nil {
466					return nil, nil, err
467				}
468				if ok {
469					contentByFile[path] = content
470				}
471			}
472			return paths, contentByFile, nil
473		}
474		paths, err := workingTreeFiles(repo)
475		if err != nil {
476			return nil, nil, err
477		}
478		contentByFile := map[string]string{}
479		for _, path := range paths {
480			content, err := os.ReadFile(filepath.Join(repo, filepath.FromSlash(path)))
481			if err != nil {
482				continue
483			}
484			contentByFile[path] = string(content)
485		}
486		return paths, contentByFile, nil
487	}
488	
489	func workingTreeFiles(repo string) ([]string, error) {
490		var paths []string
491		err := filepath.WalkDir(repo, func(path string, entry fs.DirEntry, err error) error {
492			if err != nil {
493				return err
494			}
495			name := entry.Name()
496			if entry.IsDir() {
497				switch name {
498				case ".git", "node_modules", "vendor", ".next", "dist", "build":
499					return filepath.SkipDir
500				}
501				return nil
502			}
503			if entry.Type()&fs.ModeSymlink != 0 {
504				return nil
505			}
506			rel, err := filepath.Rel(repo, path)
507			if err != nil {
508				return err
509			}
510			paths = append(paths, filepath.ToSlash(rel))
511			return nil
512		})
513		sort.Strings(paths)
514		return paths, err
515	}
