526	func importsFor(path, content string) []string {
527		switch strings.ToLower(filepath.Ext(path)) {
528		case ".go":
529			return scanGoImports(content)
530		case ".py":
531			return scanImports(content, regexp.MustCompile(`(?m)^\s*(?:from\s+([A-Za-z0-9_\.]+)\s+import|import\s+([A-Za-z0-9_\.]+))`))
532		case ".js", ".jsx", ".ts", ".tsx":
533			return scanImports(content, regexp.MustCompile(`(?m)^\s*import\s+.*?\s+from\s+['"]([^'"]+)['"]|^\s*import\s+['"]([^'"]+)['"]`))
534		case ".rs":
535			return scanImports(content, regexp.MustCompile(`(?m)^\s*use\s+([^;]+);`))
536		default:
537			return nil
538		}
539	}
540	
541	func scanGoImports(content string) []string {
542		seen := map[string]struct{}{}
543		singleImport := regexp.MustCompile(`^\s*import\s+(?:\w+\s+)?["]([^"]+)["]`)
544		blockImport := regexp.MustCompile(`^\s*(?:\w+\s+)?["]([^"]+)["]`)
545		inBlock := false
546		scanner := bufio.NewScanner(strings.NewReader(content))
547		for scanner.Scan() {
548			line := strings.TrimSpace(scanner.Text())
549			if !inBlock {
550				if strings.HasPrefix(line, "import (") {
551					inBlock = true
552					continue
553				}
554				if matches := singleImport.FindStringSubmatch(line); len(matches) > 1 {
555					seen[matches[1]] = struct{}{}
556				}
557				continue
558			}
559			if strings.HasPrefix(line, ")") {
560				inBlock = false
561				continue
562			}
563			if matches := blockImport.FindStringSubmatch(line); len(matches) > 1 {
564				seen[matches[1]] = struct{}{}
565			}
566		}
567		return sortedKeys(seen)
568	}
569	
570	func scanImports(content string, expressions ...*regexp.Regexp) []string {
571		seen := map[string]struct{}{}
572		scanner := bufio.NewScanner(strings.NewReader(content))
573		for scanner.Scan() {
574			line := scanner.Text()
575			for _, expression := range expressions {
576				matches := expression.FindStringSubmatch(line)
577				if len(matches) == 0 {
578					continue
579				}
580				for _, match := range matches[1:] {
581					if match == "" {
582						continue
583					}
584					seen[strings.TrimSpace(match)] = struct{}{}
585				}
586			}
587		}
588		return sortedKeys(seen)
589	}
590	
591	func routeLiterals(content string) []string {
592		re := regexp.MustCompile(`["'](/[A-Za-z0-9_\-/{}/:.]*)["']`)
593		seen := map[string]struct{}{}
594		for _, match := range re.FindAllStringSubmatch(content, -1) {
595			if len(match) > 1 {
596				seen[match[1]] = struct{}{}
597			}
598		}
599		return sortedKeys(seen)
600	}
