602	func looksLikeToolHandler(symbol SymbolRecord, block string) bool {
603		value := strings.ToLower(symbol.QualifiedName + "\n" + block)
604		tokens := tokenSet(value)
605		return tokens["tool"] && (tokens["handler"] || tokens["execute"] || tokens["schema"])
606	}
607	
608	func symbolBlock(content string, symbol SymbolRecord) string {
609		lines := strings.Split(content, "\n")
610		start := symbol.StartLine - 1
611		if start < 0 {
612			start = 0
613		}
614		end := symbol.EndLine
615		if end > len(lines) {
616			end = len(lines)
617		}
618		if end <= start {
619			return ""
620		}
621		return strings.Join(lines[start:end], "\n")
622	}
623	
624	func completenessLevel(failures, files int) string {
625		switch {
626		case failures == 0:
627			return "ok"
628		case files == 0 || failures*4 > files:
629			return "unsafe"
630		default:
631			return "degraded"
632		}
633	}
634	
635	func dedupeRelations(relations []RelationRecord) []RelationRecord {
636		seen := map[string]struct{}{}
637		out := make([]RelationRecord, 0, len(relations))
638		for _, relation := range relations {
639			key := relation.FromID + "\x00" + relation.ToID + "\x00" + relation.Type
640			if _, ok := seen[key]; ok {
641				continue
642			}
643			seen[key] = struct{}{}
644			out = append(out, relation)
645		}
646		return out
647	}
