670	func repoKey(ctx context.Context, repo string) string {
671		for _, remoteURL := range githubRemoteURLs(ctx, repo) {
672			if key, ok := githubRepoKey(remoteURL); ok {
673				return key
674			}
675		}
676		return "local/" + filepath.Base(repo)
677	}
678	
679	func githubRemoteURLs(ctx context.Context, repo string) []string {
680		urls, err := gitutil.RemoteURLs(ctx, repo)
681		if err != nil {
682			return nil
683		}
684		return urls
685	}
686	
687	func githubRepoKey(remoteURL string) (string, bool) {
688		remoteURL = strings.TrimSpace(strings.TrimSuffix(remoteURL, ".git"))
689		patterns := []*regexp.Regexp{
690			regexp.MustCompile(`^git@github\.com:([^/]+)/(.+)$`),
691			regexp.MustCompile(`^https://github\.com/([^/]+)/(.+)$`),
692			regexp.MustCompile(`^http://github\.com/([^/]+)/(.+)$`),
693			regexp.MustCompile(`^ssh://git@github\.com/([^/]+)/(.+)$`),
694		}
695		for _, pattern := range patterns {
696			matches := pattern.FindStringSubmatch(remoteURL)
697			if len(matches) != 3 {
698				continue
699			}
700			owner := strings.TrimSpace(matches[1])
701			name := strings.TrimSpace(matches[2])
702			if owner == "" || name == "" || strings.Contains(name, "/") {
703				continue
704			}
705			return "gh/" + owner + "/" + name, true
706		}
707		return "", false
708	}
709	
710	func containerName(qualifiedName string) string {
711		index := strings.LastIndex(qualifiedName, ".")
712		if index < 0 {
713			return ""
714		}
715		return qualifiedName[:index]
716	}
717	
718	func contentHash(content []byte) string {
719		sum := sha256.Sum256(content)
720		return hex.EncodeToString(sum[:])
721	}
722	
723	func sortedKeys(set map[string]struct{}) []string {
724		out := make([]string, 0, len(set))
725		for key := range set {
726			out = append(out, key)
727		}
728		sort.Strings(out)
729		return out
730	}
731	
732	func unsupportedLanguageHint(path string) string {
733		switch strings.ToLower(filepath.Ext(path)) {
734		case ".c", ".cc", ".cpp", ".cs", ".h", ".hpp", ".java", ".kt", ".php", ".rb", ".scala", ".swift":
735			return "unsupported source extension " + filepath.Ext(path)
736		default:
737			return ""
738		}
739	}
