1	package gitutil
2	
3	import (
4		"bytes"
5		"context"
6		"fmt"
7		"os/exec"
8		"strings"
9	)
10	
11	type ChangedFile struct {
12		Status  string `json:"status"`
13		Path    string `json:"path"`
14		OldPath string `json:"old_path,omitempty"`
15	}
16	
17	func RepoRoot(ctx context.Context, cwd string) (string, error) {
18		out, err := run(ctx, cwd, "git", "rev-parse", "--show-toplevel")
19		if err != nil {
20			return "", err
21		}
22		return strings.TrimSpace(out), nil
23	}
24	
25	func RevParse(ctx context.Context, repo, rev string) (string, error) {
26		out, err := run(ctx, repo, "git", "rev-parse", rev)
27		if err != nil {
28			return "", err
29		}
30		return strings.TrimSpace(out), nil
31	}
32	
33	func FirstParent(ctx context.Context, repo, rev string) (string, error) {
34		out, err := run(ctx, repo, "git", "rev-parse", rev+"^")
35		if err != nil {
36			return "", fmt.Errorf("resolve first parent for %s: %w", rev, err)
37		}
38		return strings.TrimSpace(out), nil
39	}
40	
41	func FindCommitWithCheckpoint(ctx context.Context, repo, checkpointID string) (string, error) {
42		out, err := run(ctx, repo, "git", "log", "--all", "--format=%H", "-n", "1", "--grep=Entire-Checkpoint: "+checkpointID)
43		if err != nil {
44			return "", err
45		}
46		commit := strings.TrimSpace(out)
47		if commit == "" {
48			return "", fmt.Errorf("checkpoint %s has no associated commit in this repository", checkpointID)
49		}
50		return commit, nil
51	}
52	
53	func ListFiles(ctx context.Context, repo, rev string) ([]string, error) {
54		out, err := run(ctx, repo, "git", "ls-tree", "-r", "--name-only", rev)
55		if err != nil {
56			return nil, err
57		}
58		var files []string
59		for _, line := range strings.Split(out, "\n") {
60			line = strings.TrimSpace(line)
61			if line != "" {
62				files = append(files, line)
63			}
64		}
65		return files, nil
66	}
67	
68	func ChangedFiles(ctx context.Context, repo, base, head string, paths []string) ([]ChangedFile, error) {
69		args := []string{"diff", "--name-status", "--find-renames", base, head, "--"}
70		args = append(args, paths...)
71		out, err := run(ctx, repo, "git", args...)
72		if err != nil {
73			return nil, err
74		}
75	
76		var files []ChangedFile
77		for _, line := range strings.Split(strings.TrimSpace(out), "\n") {
78			if strings.TrimSpace(line) == "" {
79				continue
80			}
81			fields := strings.Split(line, "\t")
82			if len(fields) < 2 {
83				continue
84			}
85			status := fields[0]
86			switch {
87			case strings.HasPrefix(status, "R") || strings.HasPrefix(status, "C"):
88				if len(fields) >= 3 {
89					files = append(files, ChangedFile{Status: status[:1], OldPath: fields[1], Path: fields[2]})
90				}
91			default:
92				files = append(files, ChangedFile{Status: status[:1], Path: fields[1]})
93			}
94		}
95		return files, nil
96	}
97	
98	func ShowFile(ctx context.Context, repo, rev, path string) (string, bool, error) {
99		out, err := run(ctx, repo, "git", "show", rev+":"+path)
100		if err != nil {
101			if strings.Contains(err.Error(), "exists on disk, but not in") ||
102				strings.Contains(err.Error(), "Path") ||
103				strings.Contains(err.Error(), "does not exist") ||
104				strings.Contains(err.Error(), "not found") {
105				return "", false, nil
106			}
107			return "", false, err
108		}
109		return out, true, nil
110	}
111	
112	func RemoteURLs(ctx context.Context, repo string) ([]string, error) {
113		out, err := run(ctx, repo, "git", "config", "--get-regexp", `^remote\..*\.url$`)
114		if err != nil {
115			return nil, err
116		}
117		origin := ""
118		var urls []string
119		for _, line := range strings.Split(strings.TrimSpace(out), "\n") {
120			fields := strings.Fields(line)
121			if len(fields) < 2 {
122				continue
123			}
124			key := fields[0]
125			url := fields[1]
126			if key == "remote.origin.url" {
127				origin = url
128				continue
129			}
130			urls = append(urls, url)
131		}
132		if origin != "" {
133			urls = append([]string{origin}, urls...)
134		}
135		return urls, nil
136	}
137	
138	func run(ctx context.Context, dir, name string, args ...string) (string, error) {
139		cmd := exec.CommandContext(ctx, name, args...)
140		cmd.Dir = dir
141		var stdout bytes.Buffer
142		var stderr bytes.Buffer
143		cmd.Stdout = &stdout
144		cmd.Stderr = &stderr
145		if err := cmd.Run(); err != nil {
146			msg := strings.TrimSpace(stderr.String())
